import HsExtensions
@testable import Unstoppable
import XCTest

final class Secp256r1VerificationFacetTests: XCTestCase {
    func testEncodeInitializeSigner() {
        let data = Secp256r1VerificationFacet.encodeInitializeSigner(publicKey: ownerPublicKey())

        XCTAssertEqual(
            data.hs.hex,
            ""
        )
    }

    func testPackSignatureRoundTrip() throws {
        let data = try Secp256r1VerificationFacet.packSignature(
            r: Data(repeating: 0x11, count: 32),
            s: Data(repeating: 0x22, count: 32),
            authenticatorData: Data(repeating: 0x33, count: 37),
            clientDataJSONPre: #"{"type":"webauthn.get","challenge":""#,
            clientDataJSONPost: #"","origin":"https://unstoppable.money","crossOrigin":false}"#
        )

        XCTAssertEqual(
            data.hs.hex,
            ""
        )
    }

    func testDummySignatureSize() {
        let signature = Secp256r1VerificationFacet.dummySignature()

        XCTAssertEqual(
            signature.hs.hex,
            ""
        )
        XCTAssertEqual(signature.count, 448)
    }

    private func ownerPublicKey() -> Data {
        Data("0411111111111111111111111111111111111111111111111111111111111111112222222222222222222222222222222222222222222222222222222222222222".hs.hexData!)
    }
}
